// generated by polka.codes
import {
  agentWorkflow,
  executeCommand,
  type FullToolInfo,
  fetchUrl,
  listFiles,
  readBinaryFile,
  readFile,
  removeFile,
  renameFile,
  replaceInFile,
  searchFiles,
  type WorkflowFn,
  writeToFile,
} from '@polka-codes/core'
import { z } from 'zod'
import { createWorkflowProgressEmitter } from '../workflow-events'
import type { CliToolRegistry } from '../workflow-tools'
import { getFixSystemPrompt, getFixUserPrompt } from './prompts'
import { type BaseWorkflowInput, getAgentWorkflowFailureMessage, getDefaultContext } from './workflow.utils'

const FIX_OUTPUT_EXCERPT_MAX_LENGTH = 4000

export type FixWorkflowInput = {
  command?: string
  task?: string
  prompt?: string
  stateless?: boolean
}

const FixIterationSummarySchema = z
  .object({
    summary: z.string().nullish(),
    bailReason: z.string().nullish(),
  })
  .refine((data) => (data.summary != null) !== (data.bailReason != null), {
    message: 'Either summary or bailReason must be provided, but not both',
  })

function buildCommandOutputExcerpt(stdout: string, stderr: string): string | undefined {
  const outputParts: string[] = []
  const trimmedStdout = stdout.trimEnd()
  const trimmedStderr = stderr.trimEnd()

  if (trimmedStdout.length > 0) {
    outputParts.push(`stdout:\n${trimmedStdout}`)
  }
  if (trimmedStderr.length > 0) {
    outputParts.push(`stderr:\n${trimmedStderr}`)
  }

  const output = outputParts.join('\n\n')
  if (output.length === 0) {
    return undefined
  }
  if (output.length <= FIX_OUTPUT_EXCERPT_MAX_LENGTH) {
    return output
  }
  const prefix = '...'
  return `${prefix}${output.slice(output.length - (FIX_OUTPUT_EXCERPT_MAX_LENGTH - prefix.length))}`
}

export const fixWorkflow: WorkflowFn<
  FixWorkflowInput & BaseWorkflowInput,
  { success: true; summaries: string[] } | { success: false; reason: string; summaries: string[] },
  CliToolRegistry
> = async (input, context) => {
  const { tools, logger, step } = context
  const { command: inputCommand, task, prompt, interactive = true, additionalTools, stateless = false } = input
  let command = inputCommand
  const summaries: string[] = []
  let formatCommand: string | undefined
  let lastExitCode = -1
  let lastOutputExcerpt: string | undefined
  const emitProgress = createWorkflowProgressEmitter(input.onWorkflowProgress, logger)

  // Helper function to build script invocation command
  const buildScriptCommand = (scriptName: string): string => {
    const runtime = process.argv[0]
    const script = process.argv[1]
    return `"${runtime}" "${script}" run ${scriptName}`
  }

  if (!command) {
    const config = input.config
    const check = config?.scripts?.check
    const test = config?.scripts?.test
    const format = config?.scripts?.format

    let checkCommand: string | undefined
    if (typeof check === 'string') {
      checkCommand = check
    } else if (check && 'command' in check) {
      checkCommand = check.command
    } else if (check && 'script' in check) {
      // For TypeScript scripts, invoke via CLI
      checkCommand = buildScriptCommand('check')
    } else if (check && 'workflow' in check) {
      // Workflows not yet supported for fix workflow
      logger.warn('Workflow scripts are not yet supported in fix workflow')
    }

    let testCommand: string | undefined
    if (typeof test === 'string') {
      testCommand = test
    } else if (test && 'command' in test) {
      testCommand = test.command
    } else if (test && 'script' in test) {
      // For TypeScript scripts, invoke via CLI
      testCommand = buildScriptCommand('test')
    } else if (test && 'workflow' in test) {
      // Workflows not yet supported for fix workflow
      logger.warn('Workflow scripts are not yet supported in fix workflow')
    }

    if (typeof format === 'string') {
      formatCommand = format
    } else if (format && 'command' in format) {
      formatCommand = format.command
    } else if (format && 'script' in format) {
      // For TypeScript scripts, invoke via CLI
      formatCommand = buildScriptCommand('format')
    } else if (format && 'workflow' in format) {
      // Workflows not yet supported for fix workflow
      logger.warn('Workflow scripts are not yet supported in fix workflow')
    }

    let defaultCommand: string | undefined
    if (checkCommand && testCommand) {
      defaultCommand = `${checkCommand} && ${testCommand}`
    } else if (checkCommand) {
      defaultCommand = checkCommand
    } else if (testCommand) {
      defaultCommand = testCommand
    }

    if (interactive) {
      command = await tools.input({
        message: 'Please enter the command to run to identify issues:',
        default: defaultCommand,
      })

      if (!command) {
        throw new Error('No command provided. Aborting.')
      }
    } else {
      command = defaultCommand
    }

    if (!command) {
      logger.info('No command to run.')
      return { success: true, summaries }
    }
  }

  await emitProgress({ kind: 'fix-started', command })

  const reportFixFailure = async (exitCode: number) => {
    await emitProgress(
      lastOutputExcerpt
        ? { kind: 'fix-failed', command, exitCode, outputExcerpt: lastOutputExcerpt }
        : { kind: 'fix-failed', command, exitCode },
    )
  }

  for (let i = 0; i < 10; i++) {
    logger.info(`Running command (attempt ${i + 1}/10): ${command}`)
    if (formatCommand) {
      await tools.executeCommand({ command: formatCommand, shell: true, pipe: true })
    }
    const { exitCode, stdout, stderr } = await tools.executeCommand({
      command,
      shell: true,
      pipe: true,
    })
    lastExitCode = exitCode
    lastOutputExcerpt = buildCommandOutputExcerpt(stdout, stderr)

    if (exitCode === 0) {
      logger.info('Command succeeded!')
      await emitProgress({ kind: 'fix-succeeded', command })
      return { success: true, summaries }
    }

    logger.info(`Command failed with exit code ${exitCode}. Asking agent to fix it...`)

    const result = await step(`fix-${i}`, async () => {
      let defaultContext = ''
      let memoryContext = ''
      if (!stateless) {
        const contextResult = await getDefaultContext(input.config, 'fix')
        defaultContext = contextResult.context
        memoryContext = await tools.getMemoryContext()
      }
      const userPrompt = getFixUserPrompt(command, exitCode, stdout, stderr, task, prompt)
      const userContent = [userPrompt, defaultContext, memoryContext].filter((part) => part.length > 0).join('\n\n')

      const agentTools: FullToolInfo[] = [
        readFile,
        writeToFile,
        replaceInFile,
        searchFiles,
        listFiles,
        executeCommand,
        fetchUrl,
        readBinaryFile,
        removeFile,
        renameFile,
      ]

      if (additionalTools?.search) {
        agentTools.push(additionalTools.search)
      }
      if (additionalTools?.mcpTools) {
        agentTools.push(...additionalTools.mcpTools)
      }

      return await agentWorkflow(
        {
          systemPrompt: getFixSystemPrompt(!stateless),
          userMessage: [
            {
              role: 'user',
              content: userContent,
            },
          ],
          tools: agentTools,
          outputSchema: FixIterationSummarySchema,
        },
        context,
      )
    })

    if (result.type !== 'Exit') {
      const reason = `Fix agent failed: ${getAgentWorkflowFailureMessage(result)}`
      logger.error(reason)
      await reportFixFailure(exitCode)
      return { success: false, summaries, reason }
    }

    const res = await step(`fix-summary-${i}`, async () => {
      if (result.object) {
        const { summary, bailReason } = result.object as z.infer<typeof FixIterationSummarySchema>

        if (bailReason) {
          logger.warn(`Agent bailed: ${bailReason}`)
          return { bailReason }
        }

        if (summary) {
          summaries.push(summary)
          if (!stateless) {
            await tools.updateMemory({ operation: 'append', content: `Summary of changes for fix attempt ${i + 1}: ${summary}` })
          }
          logger.info(`Summary of changes: ${summary}`)
        }
      }
    })

    if (res?.bailReason) {
      await reportFixFailure(exitCode)
      return { success: false, summaries, reason: res.bailReason }
    }
  }

  logger.error('Failed to fix the issue after maximum attempts.')
  await reportFixFailure(lastExitCode)
  return { success: false, summaries, reason: 'Failed to fix the issue after maximum attempts.' }
}
